import {
  forwardRef,
  useCallback,
  useState,
  type ButtonHTMLAttributes,
} from 'react';
import { cn, vc } from '../../utils/cn';
import styles from './Toggle.module.css';

export type ToggleSize = 'sm' | 'md';

export interface ToggleProps extends Omit<
  ButtonHTMLAttributes<HTMLButtonElement>,
  'onChange' | 'children'
> {
  label: string;
  checked?: boolean;
  defaultChecked?: boolean;
  size?: ToggleSize;
  onChange?: (checked: boolean) => void;
}

export const Toggle = forwardRef<HTMLButtonElement, ToggleProps>(
  function Toggle(
    {
      label,
      checked,
      defaultChecked = false,
      size = 'md',
      disabled,
      className,
      onChange,
      'data-testid': dataTestId = 'tatva-toggle',
      ...rest
    }: ToggleProps & { 'data-testid'?: string },
    ref,
  ) {
    const [internal, setInternal] = useState(defaultChecked);
    const isControlled = checked !== undefined;
    const value = isControlled ? checked : internal;

    const toggle = useCallback(() => {
      if (disabled) return;
      const next = !value;
      if (!isControlled) setInternal(next);
      onChange?.(next);
    }, [disabled, value, isControlled, onChange]);

    return (
      <button
        ref={ref}
        type="button"
        role="switch"
        aria-checked={value}
        aria-disabled={disabled || undefined}
        disabled={disabled}
        onClick={toggle}
        className={cn(
          styles.toggle,
          vc(styles, 'size', size),
          value && styles.on,
          disabled && styles.disabled,
          className,
        )}
        data-testid={dataTestId}
        {...rest}
      >
        <span className={styles.track}>
          <span className={styles.thumb} aria-hidden="true" />
        </span>
        <span className={styles.label}>{label}</span>
      </button>
    );
  },
);

.toggle {
  display: inline-flex;
  align-items: center;
  gap: var(--tatva-space-2);
  background: transparent;
  border: none;
  padding: 0;
  cursor: pointer;
  font-family: var(--tatva-font-family);
  color: var(--tatva-color-fg);
  font-size: var(--tatva-font-size-md);
}

.toggle:focus-visible .track {
  box-shadow: 0 0 0 3px var(--tatva-color-primary-200);
}

.track {
  position: relative;
  background-color: var(--tatva-color-neutral-300);
  border-radius: var(--tatva-radius-full);
  transition: background-color var(--tatva-transition-fast);
}

.sizeMd .track {
  width: 36px;
  height: 20px;
}
.sizeSm .track {
  width: 28px;
  height: 16px;
}

.thumb {
  position: absolute;
  top: 2px;
  left: 2px;
  background-color: #ffffff;
  border-radius: 50%;
  transition: transform 150ms ease;
  box-shadow: var(--tatva-shadow-sm);
}

.sizeMd .thumb {
  width: 16px;
  height: 16px;
}
.sizeSm .thumb {
  width: 12px;
  height: 12px;
}

.on .track {
  background-color: var(--tatva-color-primary-600);
}

.sizeMd.on .thumb {
  transform: translateX(16px);
}
.sizeSm.on .thumb {
  transform: translateX(12px);
}

.disabled {
  cursor: not-allowed;
  opacity: 0.55;
}

.label {
  line-height: var(--tatva-line-height-normal);
}
